/// Runs and scores a CUDA tick when both toolkit and device are present.
/// Feature/toolkit/device absence is an ordinary output row, never an error.
pub fn run_cuda_f64_accuracy_smoke() -> Result<CudaF64Outcome, CudaError> {
    let status = cuda_status();
    let CudaStatus::Available(profile) = status else {
        return Ok(CudaF64Outcome::Unavailable(status));
    };
    run_available(profile)
}

#[cfg(all(feature = "cuda", sembla_cuda_toolkit))]
fn run_available(profile: Fp64Throughput) -> Result<CudaF64Outcome, CudaError> {
    let workload = Workload::generate(accuracy_workload_config())
        .map_err(|error| CudaError::new(format!("CUDA accuracy workload failed: {error}")))?;
    let oracle = run_oracle(&workload, ACCURACY_TICK);
    let mirror = run_f64_mirror(&workload, ACCURACY_TICK);
    let output = ffi::run_tick(&workload, ACCURACY_TICK)?;
    let device = NativeF64Device {
        adapter_name: profile.device_name.clone(),
        backend: "CUDA".to_owned(),
        vendor_id: 0x10de,
        device_id: 0,
        throughput: profile,
    };
    let report = score_native(
        device,
        workload.config.rows,
        workload.config.groups,
        ACCURACY_TICK,
        &output,
        &oracle,
        &mirror,
    );
    Ok(CudaF64Outcome::Executed(report))
}

#[cfg(not(all(feature = "cuda", sembla_cuda_toolkit)))]
fn run_available(_profile: Fp64Throughput) -> Result<CudaF64Outcome, CudaError> {
    unreachable!("CUDA cannot be available without a compiled toolkit")
}

/// Benchmarks a retained CUDA workload and returns one final tick for scoring.
///
/// The C++ wrapper allocates and uploads once, executes exactly the shared
/// warmup/measured counts, records CUDA events around the three stage
/// boundaries, and performs one readback after timing.
#[allow(dead_code)]
pub(crate) fn run_cuda_f64_benchmark(
    workload: &Workload,
) -> Result<CudaBenchmarkOutcome, CudaError> {
    let status = cuda_status();
    let CudaStatus::Available(profile) = status else {
        return Ok(CudaBenchmarkOutcome::Unavailable(status));
    };
    benchmark_available(profile, workload)
}

#[cfg(all(feature = "cuda", sembla_cuda_toolkit))]
fn benchmark_available(
    profile: Fp64Throughput,
    workload: &Workload,
) -> Result<CudaBenchmarkOutcome, CudaError> {
    let (mut total_samples, mut reduce_samples, mut argmin_samples, output) =
        ffi::benchmark(workload)?;
    let timing = timing::summarize(
        workload.config.rows,
        WARMUP_TICKS,
        MEASURED_TICKS,
        TimingMethod::GpuTimestampQueries,
        &mut total_samples,
        &mut reduce_samples,
        &mut argmin_samples,
    )
    .map_err(|error| CudaError::new(format!("invalid CUDA timing samples: {error}")))?;
    Ok(CudaBenchmarkOutcome::Executed(CudaBenchmarkResult {
        profile,
        timing,
        output,
    }))
}

#[cfg(not(all(feature = "cuda", sembla_cuda_toolkit)))]
#[allow(dead_code)]
fn benchmark_available(
    _profile: Fp64Throughput,
    _workload: &Workload,
) -> Result<CudaBenchmarkOutcome, CudaError> {
    unreachable!("CUDA cannot be available without a compiled toolkit")
}

#[cfg(all(feature = "cuda", sembla_cuda_toolkit))]
mod ffi {
    use std::{ffi::CStr, os::raw::c_char};

    use super::*;

    extern "C" {
        fn sembla_cuda_f64_probe(
            name: *mut c_char,
            name_capacity: u32,
            fp32_to_fp64_ratio: *mut i32,
        ) -> i32;
        fn sembla_cuda_f64_error_string(code: i32) -> *const c_char;
        fn sembla_cuda_f64_run_tick(
            rows: u32,
            groups: u32,
            seed: u64,
            beta: f64,
            dt: f64,
            tick: u32,
            offsets: *const u32,
            employers: *const u32,
            health: *const u32,
            weights: *const f64,
            sums: *mut f64,
            winners: *mut u32,
            fired: *mut u32,
        ) -> i32;
        fn sembla_cuda_f64_benchmark(
            rows: u32,
            groups: u32,
            seed: u64,
            beta: f64,
            dt: f64,
            tick: u32,
            warmup_ticks: u32,
            measured_ticks: u32,
            offsets: *const u32,
            employers: *const u32,
            health: *const u32,
            weights: *const f64,
            total_ms: *mut f32,
            reduce_ms: *mut f32,
            argmin_ms: *mut f32,
            sums: *mut f64,
            winners: *mut u32,
            fired: *mut u32,
        ) -> i32;
    }

    pub(super) fn probe() -> CudaStatus {
        let mut name = [0_i8; 256];
        let mut ratio = 0_i32;
        // SAFETY: both output buffers are valid for the supplied capacities.
        let code =
            unsafe { sembla_cuda_f64_probe(name.as_mut_ptr(), name.len() as u32, &mut ratio) };
        if code != 0 {
            return CudaStatus::DeviceUnavailable(error_message(code));
        }
        // SAFETY: the C wrapper always NUL-terminates the fixed output buffer.
        let device_name = unsafe { CStr::from_ptr(name.as_ptr()) }
            .to_string_lossy()
            .into_owned();
        CudaStatus::Available(Fp64Throughput::from_cuda_ratio(
            device_name,
            ratio.max(0) as u32,
        ))
    }

    pub(super) fn run_tick(
        workload: &Workload,
        tick: u32,
    ) -> Result<NativeF64TickResult, CudaError> {
        let mut segmented_sums = vec![0.0_f64; workload.config.groups as usize];
        let mut winner_entity_ids = vec![u32::MAX; workload.config.groups as usize];
        let mut fired_flags = vec![0_u32; workload.config.rows as usize];
        // SAFETY: every pointer references a contiguous slice of the exact
        // rows/groups length passed to the C wrapper and remains live for the call.
        let code = unsafe {
            sembla_cuda_f64_run_tick(
                workload.config.rows,
                workload.config.groups,
                workload.config.seed,
                workload.config.beta,
                workload.config.dt,
                tick,
                workload.group_offsets.as_ptr(),
                workload.employer.as_ptr(),
                workload.health.as_ptr(),
                workload.weight.as_ptr(),
                segmented_sums.as_mut_ptr(),
                winner_entity_ids.as_mut_ptr(),
                fired_flags.as_mut_ptr(),
            )
        };
        if code != 0 {
            return Err(CudaError::new(format!(
                "CUDA native f64 tick failed: {}",
                error_message(code)
            )));
        }
        Ok(NativeF64TickResult {
            segmented_sums,
            winner_entity_ids,
            fired_flags,
        })
    }

    type BenchmarkSamples = (Vec<f64>, Vec<f64>, Vec<f64>, NativeF64TickResult);

    pub(super) fn benchmark(workload: &Workload) -> Result<BenchmarkSamples, CudaError> {
        let mut total_ms = vec![0.0_f32; MEASURED_TICKS];
        let mut reduce_ms = vec![0.0_f32; MEASURED_TICKS];
        let mut argmin_ms = vec![0.0_f32; MEASURED_TICKS];
        let mut segmented_sums = vec![0.0_f64; workload.config.groups as usize];
        let mut winner_entity_ids = vec![u32::MAX; workload.config.groups as usize];
        let mut fired_flags = vec![0_u32; workload.config.rows as usize];
        // SAFETY: all input/output slices remain alive for the call and have the
        // exact rows/groups/sample lengths communicated to the C wrapper.
        let code = unsafe {
            sembla_cuda_f64_benchmark(
                workload.config.rows,
                workload.config.groups,
                workload.config.seed,
                workload.config.beta,
                workload.config.dt,
                BENCHMARK_TICK,
                WARMUP_TICKS as u32,
                MEASURED_TICKS as u32,
                workload.group_offsets.as_ptr(),
                workload.employer.as_ptr(),
                workload.health.as_ptr(),
                workload.weight.as_ptr(),
                total_ms.as_mut_ptr(),
                reduce_ms.as_mut_ptr(),
                argmin_ms.as_mut_ptr(),
                segmented_sums.as_mut_ptr(),
                winner_entity_ids.as_mut_ptr(),
                fired_flags.as_mut_ptr(),
            )
        };
        if code != 0 {
            return Err(CudaError::new(format!(
                "CUDA native f64 benchmark failed: {}",
                error_message(code)
            )));
        }
        Ok((
            total_ms.into_iter().map(f64::from).collect(),
            reduce_ms.into_iter().map(f64::from).collect(),
            argmin_ms.into_iter().map(f64::from).collect(),
            NativeF64TickResult {
                segmented_sums,
                winner_entity_ids,
                fired_flags,
            },
        ))
    }

    fn error_message(code: i32) -> String {
        // SAFETY: CUDA returns a process-lifetime string for every error code.
        let pointer = unsafe { sembla_cuda_f64_error_string(code) };
        if pointer.is_null() {
            return format!("CUDA error {code}");
        }
        // SAFETY: non-null CUDA error strings are NUL-terminated.
        let text = unsafe { CStr::from_ptr(pointer) }.to_string_lossy();
        format!("{text} (code {code})")
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cuda_absence_is_a_reported_no_op() {
        let status = cuda_status();
        println!("{status}");
        let outcome = run_cuda_f64_accuracy_smoke().unwrap();
        println!("{outcome}");
        match outcome {
            CudaF64Outcome::Unavailable(unavailable) => assert!(!unavailable.is_available()),
            CudaF64Outcome::Executed(report) => report.assert_expected().unwrap(),
        }
    }

    #[test]
    fn benchmark_absence_is_a_reported_no_op() {
        if cuda_status().is_available() {
            return;
        }
        let workload =
            Workload::generate(crate::workload::WorkloadConfig::with_size(1_000, 50)).unwrap();
        let outcome = run_cuda_f64_benchmark(&workload).unwrap();
        assert!(matches!(outcome, CudaBenchmarkOutcome::Unavailable(_)));
    }
}

