fn binary_expr_eq(lhs_left: &Expr, lhs_right: &Expr, rhs_left: &Expr, rhs_right: &Expr) -> bool {
    expr_structural_eq(lhs_left, rhs_left) && expr_structural_eq(lhs_right, rhs_right)
}

fn expr_structural_eq(lhs: &Expr, rhs: &Expr) -> bool {
    match (lhs, rhs) {
        (Expr::Real { value: lhs }, Expr::Real { value: rhs }) => lhs.to_bits() == rhs.to_bits(),
        (Expr::Int { value: lhs }, Expr::Int { value: rhs }) => lhs == rhs,
        (Expr::Bool { value: lhs }, Expr::Bool { value: rhs }) => lhs == rhs,
        (Expr::Enum { variant: lhs }, Expr::Enum { variant: rhs }) => lhs == rhs,
        (Expr::Param { name: lhs }, Expr::Param { name: rhs }) => lhs == rhs,
        (Expr::SelfAttr { name: lhs }, Expr::SelfAttr { name: rhs }) => lhs == rhs,
        (
            Expr::Add {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Add {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Sub {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Sub {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Mul {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Mul {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Div {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Div {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Eq {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Eq {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Ne {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Ne {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Lt {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Lt {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Le {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Le {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Gt {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Gt {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Ge {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Ge {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::And {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::And {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Or {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Or {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        ) => binary_expr_eq(lhs_left, lhs_right, rhs_left, rhs_right),
        (Expr::Not { expr: lhs }, Expr::Not { expr: rhs }) => expr_structural_eq(lhs, rhs),
        (
            Expr::EnumIs {
                attr: lhs_attr,
                variant: lhs_variant,
            },
            Expr::EnumIs {
                attr: rhs_attr,
                variant: rhs_variant,
            },
        ) => lhs_attr == rhs_attr && lhs_variant == rhs_variant,
        (
            Expr::Input {
                port: lhs_port,
                agg: lhs_agg,
            },
            Expr::Input {
                port: rhs_port,
                agg: rhs_agg,
            },
        ) => lhs_port == rhs_port && aggregate_structural_eq(lhs_agg, rhs_agg),
        (
            Expr::Agg {
                op: lhs_op,
                table: lhs_table,
                on: lhs_on,
                filter: lhs_filter,
            },
            Expr::Agg {
                op: rhs_op,
                table: rhs_table,
                on: rhs_on,
                filter: rhs_filter,
            },
        ) => {
            lhs_table == rhs_table
                && lhs_on == rhs_on
                && agg_op_structural_eq(lhs_op, rhs_op)
                && expr_structural_eq(lhs_filter, rhs_filter)
        }
        _ => false,
    }
}

