 78	                                     double* sums) {
 79	  const uint32_t group = blockIdx.x * blockDim.x + threadIdx.x;
 80	  if (group < groups) sums[group] = partials[group * 2u] + partials[group * 2u + 1u];
 81	}
 82	
 83	__global__ void map_kernel(
 84	    uint32_t rows, uint32_t tick, uint32_t seed_lo, uint32_t seed_hi,
 85	    double beta, double dt, const uint32_t* offsets,
 86	    const uint32_t* employers, const uint32_t* health, const double* sums,
 87	    double* races, uint32_t* fired) {
 88	  const uint32_t row = blockIdx.x * blockDim.x + threadIdx.x;
 89	  if (row >= rows) return;
 90	  fired[row] = 0u;
 91	  races[row] = CUDART_INF;
 92	  if (health[row] != kSusceptible) return;
 93	  const uint32_t group = employers[row];
 94	  const double group_size = static_cast<double>(offsets[group + 1u] - offsets[group]);
 95	  const double lambda = beta * sums[group] / group_size;
 96	  if (!(lambda > 0.0)) return;
 97	  const double uniform = uniform_open_f64(
 98	      philox4x32_10(seed_lo, seed_hi, tick, kInfectionRule, row, 0u));
 99	  const double time = -log(1.0 - uniform) / lambda;
100	  races[row] = time;
101	  if (time < dt && !contested(row)) fired[row] = 1u;
102	}
103	
104	__global__ void argmin_kernel(uint32_t groups, double dt,
105	                              const uint32_t* offsets, const double* races,
106	                              uint32_t* winners, uint32_t* fired) {
107	  const uint32_t group = blockIdx.x * blockDim.x + threadIdx.x;
108	  if (group >= groups) return;
109	  uint64_t best_bits = UINT64_MAX;
110	  uint32_t best_rule = UINT32_MAX;
111	  uint32_t best_entity = kNoWinner;
112	  for (uint32_t row = offsets[group]; row < offsets[group + 1u]; ++row) {
113	    const double time = races[row];
114	    if (!contested(row) || !(time < dt)) continue;
115	    const uint64_t bits = static_cast<uint64_t>(__double_as_longlong(time));
116	    const bool better = bits < best_bits ||
117	        (bits == best_bits &&
118	         (kInfectionRule < best_rule ||
119	          (kInfectionRule == best_rule && row < best_entity)));
120	    if (better) {
121	      best_bits = bits;
122	      best_rule = kInfectionRule;
123	      best_entity = row;
124	    }
125	  }
126	  winners[group] = best_entity;
127	  if (best_entity != kNoWinner) fired[best_entity] = 1u;
128	}
129	
130	struct TickConfig {
131	  uint32_t rows;
132	  uint32_t groups;
133	  uint64_t seed;
134	  double beta;
135	  double dt;
136	  uint32_t tick;
137	};
