 77	fn find_nvcc() -> Option<PathBuf> {
 78	    if let Some(path) = env::var_os("NVCC").map(PathBuf::from) {
 79	        return Some(path);
 80	    }
 81	    if let Some(home) = env::var_os("CUDA_HOME") {
 82	        let candidate = PathBuf::from(home).join("bin").join(executable("nvcc"));
 83	        if candidate.is_file() {
 84	            return Some(candidate);
 85	        }
 86	    }
 87	    env::var_os("PATH").and_then(|path| {
 88	        env::split_paths(&path)
 89	            .map(|directory| directory.join(executable("nvcc")))
 90	            .find(|candidate| candidate.is_file())
 91	    })
 92	}
