 12	namespace {
 13	
 14	constexpr uint32_t kInfectious = 1u;
 15	constexpr uint32_t kSusceptible = 0u;
 16	constexpr uint32_t kInfectionRule = 0u;
 17	constexpr uint32_t kNoWinner = 0xffffffffu;
 18	constexpr uint32_t kPhiloxM0 = 0xd2511f53u;
 19	constexpr uint32_t kPhiloxM1 = 0xcd9e8d57u;
 20	constexpr uint32_t kPhiloxW0 = 0x9e3779b9u;
 21	constexpr uint32_t kPhiloxW1 = 0xbb67ae85u;
 22	constexpr uint32_t kThreads = 256u;
 23	
 24	struct Words4 {
 25	  uint32_t x, y, z, w;
 26	};
 27	
 28	__device__ Words4 philox4x32_10(uint32_t seed_lo, uint32_t seed_hi,
 29	                                 uint32_t tick, uint32_t rule_id,
 30	                                 uint32_t entity_id, uint32_t draw_idx) {
 31	  Words4 counter{tick, rule_id, entity_id, draw_idx};
 32	  uint32_t key_x = seed_lo;
 33	  uint32_t key_y = seed_hi;
 34	  for (uint32_t round = 0; round < 10; ++round) {
 35	    const uint32_t low0 = kPhiloxM0 * counter.x;
 36	    const uint32_t high0 = __umulhi(kPhiloxM0, counter.x);
 37	    const uint32_t low1 = kPhiloxM1 * counter.z;
 38	    const uint32_t high1 = __umulhi(kPhiloxM1, counter.z);
 39	    counter = Words4{high1 ^ counter.y ^ key_x, low1,
 40	                     high0 ^ counter.w ^ key_y, low0};
 41	    if (round != 9) {
 42	      key_x += kPhiloxW0;
 43	      key_y += kPhiloxW1;
 44	    }
 45	  }
 46	  return counter;
 47	}
 48	
 49	__device__ double uniform_open_f64(Words4 words) {
 50	  const uint64_t mantissa = (static_cast<uint64_t>(words.x) << 21) |
 51	                            (static_cast<uint64_t>(words.y) >> 11);
 52	  const double sample = (static_cast<double>(mantissa) + 0.5) *
 53	                        1.1102230246251565e-16;
 54	  return sample == 1.0 ? nextafter(1.0, 0.0) : sample;
 55	}
 56	
 57	__device__ bool contested(uint32_t entity) { return entity % 10u == 5u; }
 58	
 59	__global__ void reduce_partial_kernel(
 60	    uint32_t groups, const uint32_t* offsets, const uint32_t* health,
 61	    const double* weights, double* partials) {
 62	  const uint32_t partial = blockIdx.x * blockDim.x + threadIdx.x;
 63	  if (partial >= groups * 2u) return;
 64	  const uint32_t group = partial / 2u;
 65	  const uint32_t start = offsets[group];
 66	  const uint32_t end = offsets[group + 1u];
 67	  const uint32_t midpoint = start + (end - start) / 2u;
 68	  const uint32_t begin = partial % 2u == 0u ? start : midpoint;
 69	  const uint32_t finish = partial % 2u == 0u ? midpoint : end;
 70	  double sum = 0.0;
 71	  for (uint32_t row = begin; row < finish; ++row) {
 72	    if (health[row] == kInfectious) sum += weights[row];
 73	  }
 74	  partials[partial] = sum;
 75	}
 76	
 77	__global__ void reduce_finish_kernel(uint32_t groups, const double* partials,
 78	                                     double* sums) {
 79	  const uint32_t group = blockIdx.x * blockDim.x + threadIdx.x;
 80	  if (group < groups) sums[group] = partials[group * 2u] + partials[group * 2u + 1u];
 81	}
 82	
 83	__global__ void map_kernel(
 84	    uint32_t rows, uint32_t tick, uint32_t seed_lo, uint32_t seed_hi,
 85	    double beta, double dt, const uint32_t* offsets,
 86	    const uint32_t* employers, const uint32_t* health, const double* sums,
 87	    double* races, uint32_t* fired) {
 88	  const uint32_t row = blockIdx.x * blockDim.x + threadIdx.x;
 89	  if (row >= rows) return;
 90	  fired[row] = 0u;
 91	  races[row] = CUDART_INF;
 92	  if (health[row] != kSusceptible) return;
 93	  const uint32_t group = employers[row];
 94	  const double group_size = static_cast<double>(offsets[group + 1u] - offsets[group]);
 95	  const double lambda = beta * sums[group] / group_size;
 96	  if (!(lambda > 0.0)) return;
 97	  const double uniform = uniform_open_f64(
 98	      philox4x32_10(seed_lo, seed_hi, tick, kInfectionRule, row, 0u));
 99	  const double time = -log(1.0 - uniform) / lambda;
100	  races[row] = time;
101	  if (time < dt && !contested(row)) fired[row] = 1u;
102	}
103	
104	__global__ void argmin_kernel(uint32_t groups, double dt,
105	                              const uint32_t* offsets, const double* races,
106	                              uint32_t* winners, uint32_t* fired) {
107	  const uint32_t group = blockIdx.x * blockDim.x + threadIdx.x;
108	  if (group >= groups) return;
109	  uint64_t best_bits = UINT64_MAX;
110	  uint32_t best_rule = UINT32_MAX;
111	  uint32_t best_entity = kNoWinner;
112	  for (uint32_t row = offsets[group]; row < offsets[group + 1u]; ++row) {
113	    const double time = races[row];
114	    if (!contested(row) || !(time < dt)) continue;
115	    const uint64_t bits = static_cast<uint64_t>(__double_as_longlong(time));
116	    const bool better = bits < best_bits ||
117	        (bits == best_bits &&
118	         (kInfectionRule < best_rule ||
119	          (kInfectionRule == best_rule && row < best_entity)));
120	    if (better) {
121	      best_bits = bits;
122	      best_rule = kInfectionRule;
123	      best_entity = row;
124	    }
125	  }
126	  winners[group] = best_entity;
127	  if (best_entity != kNoWinner) fired[best_entity] = 1u;
128	}
